#include<iostream>
#include<cstring>
#include<algorithm>
using namespace std;

const int N = 3000 + 5;

struct Thing
{
	int w, r;
}a[N];

bool cmp(Thing x, Thing y)
{
	return x.r > y.r;
}

int dp[N][N];

int main() {
	int n;
	cin >> n;
	for(int i = 1; i <= n; i++)
		cin >> a[i].w >> a[i].r;
	sort(a + 1, a + n + 1, cmp);
	dp[1][1] = a[1].w;
	for(int i = 1; i <= n; i++)
		for(int j = 1; j <= i; j++)
			dp[i][j] = max(dp[i - 1][j], dp[i - 1][j - 1] + a[i].w - a[i].r * (j - 1));
	int ans = 0;
	for(int i = 1; i <= n; i++)
		if(dp[n][i] > ans)
			ans = dp[n][i];
	cout << ans;
    return 0;
}
